                is_position: [
                    { required: true, message: '请选择是否持仓', trigger: 'change' }
                ],
            },
            activeName: '全部',
            tabAccountId: 10,
            accountList: [],
            InoutGoldList: [],
            InoutGoldCurrPage: 1, //当前页
            InoutGoldPageSize: 20, //每页显示条数
            InoutGoldTotal: 1, //总条数
            accountBalanceDetailsShow: false,
            accountBalanceDetailsList: [],
            accountBalanceDetailsPage: 1,
            accountBalanceDetailsLimit: 20,
            accountBalanceDetailsTotal: 0, //总条数
            currencyList: [],
            currency: '',
            accountBalanceTabValue: '',

            currencyPositionsList: [],
            currencyPositionsPage: 1,
            currencyPositionsLimit: 20,
            currencyPositionsTotal: 0, //总条数

            accountCurrencyDetailsShow: false,
            accountCurrencyDetailsList: [],
            accountCurrencyDetailsPage: 1,
            accountCurrencyDetailsLimit: 20,
            accountCurrencyDetailsTotal: 0, //总条数
            selectCurrency: '',

            profitGoldCurrPage: 1, //当前页
            profitGoldPageSize: 20, //每页显示条数
            profitGoldTotal: 1, //总条数
            profitGoldList: [],

            maxMinUplRateShow: false,
            maxMinUplRateLimit: 20,
            maxMinUplRatePage: 1,
            maxMinUplRateList: [],
            maxMinUplRateTotal: 0,
            addQuantityAccountShow: false,
            accountForm: {
                name: '',
                api_key: '',
                secret_key: '',
                pass_phrase: '',
                type: '',
                is_position: '1',
            },
            cachePositionDialogVisible: false,
            cachePositionActiveTab: 'current',
            cacheCurrentLoading: false,
            cacheHistoryLoading: false,
            cacheCurrentPositionsList: [],
            cacheCurrentPositionsCurrPage: 1,
            cacheCurrentPositionsPageSize: 10,
            cacheCurrentPositionsTotal: 0,
            cacheHistoryPositionsList: [],
            cacheHistoryPage: 1,
            cacheHistoryPageSize: 10,
            cacheHistoryTotal: 0,
            cachePositionRow: null,
            cachePositionDataCache: {},
        }
    },
    computed: {
        cachePositionDialogTitle() {
            return this.activeName + ' 缓存持仓详情';
        },
        cachePositionSummaryValue() {
            if (!this.cachePositionRow) {
                return '-';
            }
            return this.keepDecimalNotRounding(this.cachePositionRow.yubibao_balance, 2, true);
        },
        pagedCacheCurrentPositionsList() {
            var start = (this.cacheCurrentPositionsCurrPage - 1) * this.cacheCurrentPositionsPageSize;
            var end = start + this.cacheCurrentPositionsPageSize;
            return this.cacheCurrentPositionsList.slice(start, end);
        },
        pagedCacheHistoryPositionsList() {
            var start = (this.cacheHistoryPage - 1) * this.cacheHistoryPageSize;
            var end = start + this.cacheHistoryPageSize;
            return this.cacheHistoryPositionsList.slice(start, end);
        },
    },
    created() {
        this.getAccountList();
    },
    watch: {
        userOkxId: {
            handler: function (val, oldVal) {
                if(val) {
                }
            },
            immediate: true,
        },
    },
    components: {
        "wbc-page": Page, //加载分页组件
    },
    methods: {
        getAllList(ServerWhere) {
            if (!ServerWhere || ServerWhere == undefined || ServerWhere.length <= 0) {
                ServerWhere = {
                    limit: this.pageSize,
                    page: this.currPage,
                };
            }
            this.loading = true;
            get("/Grid/QuantifyAccount/getQuantifyAccountDateAllList", ServerWhere, json => {
                if (json.data.code == 10000) {
                    if (json.data.data) {
                        let list = (json.data && json.data.data.data) || [];
                        console.log(list);
                        if(this.isMobel) {
                            if (this.currPage <= 1) {
                                // console.log('首次加载');
                                this.tableData = list;
                                // this.$forceUpdate();
                            } else {
                                // console.log('二次加载');
                                if (ServerWhere.page <= json.data.data.allpage) {
                                    // console.log(ServerWhere.page, json.data.allpage);
                                    this.tableData = [...this.tableData, ...list];
                                    // this.$forceUpdate();
                                }
                            }
                            this.currPage += 1;
                            if (ServerWhere.page >= json.data.data.allpage) {
                                // console.log(ServerWhere.page, json.data.allpage);
                                this.finished = true;
                            } else {
                                this.finished = false;
                            }
                        } else {
                            this.tableData = list;
                        }
                    }

                    this.total = json.data.data.count;
                } else {
                    this.$message.error("加载数据失败");
                }
                this.loading = false;
            });
        },
        getList(ServerWhere) {
            if (!ServerWhere || ServerWhere == undefined || ServerWhere.length <= 0) {
                ServerWhere = {
                    limit: this.pageSize,
                    page: this.currPage,
                    account_id: this.tabAccountId,
                };
            }
            // console.log(ServerWhere);
            this.loading = true;
            get("/Grid/QuantifyAccount/getQuantifyAccountDateList", ServerWhere, json => {
                console.log(json.data);
                if (json.data.code == 10000) {
                    if (json.data.data) {
                        let list = (json.data && json.data.data.data) || [];
                        if(this.isMobel) {
                            if (this.currPage <= 1) {
                                // console.log('首次加载');
                                this.tableData = list;
                                // this.$forceUpdate();
                            } else {
                                // console.log('二次加载');
                                if (ServerWhere.page <= json.data.allpage) {
                                    // console.log(ServerWhere.page, json.data.allpage);
                                    this.tableData = [...this.tableData, ...list];
                                    // this.$forceUpdate();
                                }
                            }
                            this.currPage += 1;
                            if (ServerWhere.page >= json.data.allpage) {
                                // console.log(ServerWhere.page, json.data.allpage);
                                this.finished = true;
                            } else {
                                this.finished = false;
                            }
                        } else {
                            this.tableData = list;
                        }
                    }
                    this.total = json.data.data.count;
                } else {
                    this.$message.error("加载数据失败");
                }
                this.loading = false;
            });
        },
        getAccountList() {
            get("/Grid/QuantifyAccount/getAccountPrincipalList", {
                user_id: this.userOkxId
            }, json => {
                console.log(json.data);
                if (json.data.code == 10000) {
                    this.accountList = [{ id: 0, name: '全部' }, ...json.data.data]; // Add default object
                    this.getAllList();
                }
            })
        },
        accountBalanceDetailsFun(account_id) { //余额明细数据
            // console.log(account_id);
            // this.accountBalanceTabValue = '1'
            get("/Grid/QuantifyAccount/getQuantifyAccountDetails", {
                account_id: this.tabAccountId,
                limit: this.accountBalanceDetailsLimit,
                page: this.accountBalanceDetailsPage,
                currency: this.currency,
            }, json => {
                console.log(json.data);
                if (json.data.code == 10000) {
                    this.accountBalanceDetailsList = json.data.data.lists;
                    this.accountBalanceDetailsTotal = json.data.data.count;
                    if(this.tabAccountId) {
                        this.getCurrencyList();
                    }
                }
            })
        },
        getCurrencyList() {
            get("/Grid/QuantifyAccount/getQuantifyAccountCurrencyList", {
                account_id: this.tabAccountId,
            }, json => {
                console.log(json.data);
                if (json.data.code == 10000) {
                    this.currencyList = json.data.data;
                }
            })
        },
        selectCurrencyChange() { //根据币种选择对应的账户余额明细数据
            this.accountBalanceDetailsFun();
        },
        getAccountCurrencyDetailsShow(currency) { //获取账户币种交易明细数据
            this.accountCurrencyDetailsList = [];
            this.accountCurrencyDetailsShow = true;
            this.selectCurrency = currency;
            this.accountCurrencyDetailsPage = 1;
            this.accountCurrencyDetailsTotal = 0;
            this.getAccountCurrencyDetailsList();
        },
        getAccountCurrencyDetailsList() { //获取账户币种交易明细数据
            this.loading = true;
            get("/Grid/QuantifyAccount/getAccountCurrencyDetailsList", {
                limit: this.accountCurrencyDetailsLimit,
                page: this.accountCurrencyDetailsPage,
                account_id: this.tabAccountId,
                currency: this.selectCurrency,
            }, json => {
                console.log(json.data.data);
                this.loading = false;
                if (json.data.code == 10000) {
                    this.accountCurrencyDetailsList = json.data.data.data;
                    this.accountCurrencyDetailsTotal = json.data.data.count;
                }
            })
        },

        limitPaging(limit) {
            //赋值当前条数
            this.pageSize = limit;
            this.getList(); //刷新列表
        },
        skipPaging(page) {
            //赋值当前页数
            this.currPage = page;
            this.getList(); //刷新列表
        },
        copySuccess() {
            this.$message({
                message: 'Copy successfully!',
                type: 'success'
            });
        },
        submitForm(formName) { //出入金
            this.$refs[formName].validate((valid) => {
                if (valid) {
                    const loading = this.$loading({
                        target: '.el-dialog',
                    });
                    get('/Grid/QuantifyAccount/calcDepositAndWithdrawal', {
                        account_id: this.tabAccountId,
                        direction: this.ruleForm.direction,
                        amount: this.ruleForm.amount,
                        remark: this.ruleForm.remark,
                    }, (json) => {
                        console.log(json);
                        if (json.data && json.data.code == 10000) {
                            this.$message.success('更新成功');
                            this.$refs[formName].resetFields();
                            loading.close();
                            this.dialogVisibleShow = false;
                            this.getList();
                        } else {
                            loading.close();
                            this.$message.error(json.data.data.msg);
                        }
                    })
                } else {
                    console.log('error submit!!');
                    return false;
                }
            });
        },
        addAccountSubmitForm(formName) { //添加账户
            this.$refs[formName].validate((valid) => {
                if (valid) {
                    const loading = this.$loading({
                        target: '.el-dialog',
                    });
                    post('/Grid/QuantifyAccount/addQuantityAccount', this.accountForm, (json) => {
                        console.log(json);
                        if (json.data && json.data.code == 10000) {
                            this.$message.success('更新成功');
                            this.$refs[formName].resetFields();
                            loading.close();
                            this.dialogVisibleShow = false;
                            this.getList();
                        } else {
                            loading.close();
                            this.$message.error(json.data.data.msg);
                        }
                    })
                } else {
                    console.log('error submit!!');
                    return false;
                }
            });
        },
        dialogVisibleListClick() {
            this.dialogVisibleListShow = true;
            this.getInoutGoldList();
        },
        accountBalanceTabClick(tab) {
            console.log(tab);
            this.currencyPositionsList = [];
            this.accountBalanceDetailsList = [];
            if(tab.name == 1) {
                // this.accountBalanceTabValue = '1'
                this.accountBalanceDetailsFun();
            }
            if(tab.name == 2) {
                // this.accountBalanceTabValue = '2'
                this.getAccountCurrencyPositionsList();
            }
            if(tab.name == 3) {
                this.getMaxMinUplRate();
            }
        },
        getTotalBalanceClick() { //获取总结余弹框
            if(this.activeName == '全部') {
               return; 
            }
            this.currencyPositionsList = [];
            this.accountBalanceDetailsList = [];
            this.accountBalanceTabValue = '1'
            this.accountBalanceDetailsFun();
            this.accountBalanceDetailsShow = true;
        },
        openCachePositionDialog(row) {
            if(this.activeName == '全部' || !this.tabAccountId) {
                return;
            }
            this.cachePositionRow = row || null;
            this.cachePositionDialogVisible = true;
            this.cachePositionActiveTab = 'current';
            this.cacheCurrentPositionsCurrPage = 1;
            this.cacheHistoryPage = 1;
            this.restoreCachePositionData();
            this.getCacheCurrentPositionsList();
        },
        handleCachePositionTabClick(tab) {
            if(tab.name === 'history' && !this.cacheHistoryPositionsList.length) {
                this.getCacheHistoryPositionsList();
            }
        },
        handleCachePositionDialogClose() {
            this.cachePositionDialogVisible = false;
            this.cachePositionActiveTab = 'current';
            this.cacheCurrentLoading = false;
            this.cacheHistoryLoading = false;
            this.cacheCurrentPositionsList = [];
            this.cacheCurrentPositionsCurrPage = 1;
            this.cacheCurrentPositionsTotal = 0;
            this.cacheHistoryPositionsList = [];
            this.cacheHistoryPage = 1;
            this.cacheHistoryTotal = 0;
            this.cachePositionRow = null;
        },
        getCacheCurrentPositionsList() {
            if(!this.tabAccountId) {
                this.cacheCurrentPositionsList = [];
                this.cacheCurrentPositionsTotal = 0;
                return;
            }
            const accountCache = this.getCachePositionDataBucket();
            if (accountCache.currentLoaded) {
                this.cacheCurrentPositionsList = accountCache.currentRows.slice();
                this.cacheCurrentPositionsTotal = accountCache.currentTotal;
                this.cacheCurrentPositionsCurrPage = 1;
                return;
            }
            this.cacheCurrentLoading = true;
            get("/sigadmin/get_current_positions", {
                account_id: this.tabAccountId,
            }, json => {
                this.cacheCurrentLoading = false;
                if (json.status == 200) {
                    this.cacheCurrentPositionsList = Array.isArray(json.data.data) ? json.data.data : [];
                    this.cacheCurrentPositionsTotal = this.cacheCurrentPositionsList.length;
                    this.cacheCurrentPositionsCurrPage = 1;
                    const nextCache = this.getCachePositionDataBucket();
                    nextCache.currentRows = this.cacheCurrentPositionsList.slice();
                    nextCache.currentTotal = this.cacheCurrentPositionsTotal;
                    nextCache.currentLoaded = true;
                } else {
                    this.cacheCurrentPositionsList = [];
                    this.cacheCurrentPositionsTotal = 0;
                    this.$message.error("加载当前持仓失败");
                }
            });
        },
        getCacheHistoryPositionsList() {
            if(!this.tabAccountId) {
                this.cacheHistoryPositionsList = [];
                this.cacheHistoryTotal = 0;
                return;
            }
            const accountCache = this.getCachePositionDataBucket();
            if (accountCache.historyLoaded) {
                this.cacheHistoryPositionsList = accountCache.historyRows.slice();
                this.cacheHistoryTotal = accountCache.historyTotal;
                this.cacheHistoryPage = 1;
                return;
            }
            this.cacheHistoryLoading = true;
            get("/sigadmin/get_positions_history", {
                account_id: this.tabAccountId,
                limit: this.cacheHistoryPageSize,
                page: this.cacheHistoryPage,
            }, json => {
                this.cacheHistoryLoading = false;
                if (json.status == 200) {
                    this.cacheHistoryPositionsList = Array.isArray(json.data.data) ? json.data.data : [];
                    this.cacheHistoryTotal = this.cacheHistoryPositionsList.length;
                    const nextCache = this.getCachePositionDataBucket();
                    nextCache.historyRows = this.cacheHistoryPositionsList.slice();
                    nextCache.historyTotal = this.cacheHistoryTotal;
                    nextCache.historyLoaded = true;
                } else {
                    this.cacheHistoryPositionsList = [];
                    this.cacheHistoryTotal = 0;
                    this.$message.error("加载历史持仓失败");
                }
            });
        },
        getCachePositionDataBucket() {
            const cacheKey = String(this.tabAccountId || '');
            if (!cacheKey) {
                return {
                    currentRows: [],
                    currentTotal: 0,
                    currentLoaded: false,
                    historyRows: [],
                    historyTotal: 0,
                    historyLoaded: false,
                };
            }
            if (!this.cachePositionDataCache[cacheKey]) {
                this.$set(this.cachePositionDataCache, cacheKey, {
                    currentRows: [],
                    currentTotal: 0,
                    currentLoaded: false,
                    historyRows: [],
                    historyTotal: 0,
                    historyLoaded: false,
                });
            }
            return this.cachePositionDataCache[cacheKey];
        },
        restoreCachePositionData() {
            const accountCache = this.getCachePositionDataBucket();
            this.cacheCurrentPositionsList = accountCache.currentRows.slice();
            this.cacheCurrentPositionsTotal = accountCache.currentTotal;
            this.cacheHistoryPositionsList = accountCache.historyRows.slice();
            this.cacheHistoryTotal = accountCache.historyTotal;
        },
        changeCacheCurrentPositionsLimit(limit) {
            this.cacheCurrentPositionsPageSize = limit;
            this.cacheCurrentPositionsCurrPage = 1;
        },
        changeCacheCurrentPositionsPage(page) {
            this.cacheCurrentPositionsCurrPage = page;
        },
        changeCacheHistoryLimit(limit) {
            this.cacheHistoryPageSize = limit;
            this.cacheHistoryPage = 1;
        },
        changeCacheHistoryPage(page) {
            this.cacheHistoryPage = page;
        },
        getCachePositionOpenTime(row) {
            const info = (row || {}).info || {};
            const rawTime = info.cTime || row.timestamp || row.datetime || '';
            if (!rawTime) return '-';
            return this.normalizePositionTime(rawTime);
        },
        getCacheHistoryOpenTime(row) {
            const info = this.getCacheHistoryInfo(row);
            const rawTime = info.cTime || row.timestamp || row.datetime || '';
            if (!rawTime) return '-';
            return this.normalizePositionTime(rawTime);
        },
        getCacheHistoryCloseTime(row) {
            const info = this.getCacheHistoryInfo(row);
            const rawTime = info.uTime || row.infoTime || row.lastTradeTimestamp || '';
            if (!rawTime) return '-';
            return this.normalizePositionTime(rawTime);
        },
        getCacheHistoryInfo(row) {
            return row && row.info ? row.info : {};
        },
        getCacheHistoryStatus(row) {
            const type = this.getCacheHistoryInfo(row).type;
            if (type === '1') return '部分平仓';
            if (type === '2') return '完全平仓';
            if (type === '3') return '强平';
            if (type === '4') return '强减';
            if (type === '5') return 'ADL自动减仓';
            return '-';
        },
        getCacheHistoryDirection(row) {
            const info = this.getCacheHistoryInfo(row);
            if (info.direction === 'long' && info.posSide === 'long') return '买入开多';
            if (info.direction === 'long' && info.posSide === 'short') return '买入平空';
            if (info.direction === 'short' && info.posSide === 'long') return '卖出平多';
            if (info.direction === 'short' && info.posSide === 'short') return '卖出开空';
            return '-';
        },
        normalizePositionTime(rawTime) {
            if (!rawTime) return '-';
            if (typeof rawTime === 'string' && rawTime.indexOf('-') > -1) {
                return rawTime;
            }
            const num = Number(rawTime);
            if (!num || isNaN(num)) {
                return rawTime;
            }
            const timestamp = String(rawTime).length === 13 ? num : num * 1000;
            const date = new Date(timestamp);
            if (isNaN(date.getTime())) {
                return rawTime;
            }
            const pad = (value) => String(value).padStart(2, '0');
            return `${date.getFullYear()}-${pad(date.getMonth() + 1)}-${pad(date.getDate())} ${pad(date.getHours())}:${pad(date.getMinutes())}:${pad(date.getSeconds())}`;
        },
        formatCacheHistoryPnlRate(row) {
            const contractSize = Number(row.contractSize) || 0;
            const entryPrice = Number(row.entryPrice) || 0;
            const realizedPnl = Number(row.realizedPnl) || 0;
            const base = contractSize * entryPrice;
            if (!base) {
                return '-';
            }
            return this.keepDecimalNotRounding(realizedPnl / base * 100, 2, true) + '%';
        },
        getAccountCurrencyPositionsList() {
            get("/Grid/QuantifyAccount/getAccountCurrencyPositionsList", {
                limit: this.currencyPositionsLimit,
                page: this.currencyPositionsPage,
                account_id: this.tabAccountId,
                currency: 'BTC',
            }, json => {
                console.log(json);
                if (json.data.code == 10000) {
                    this.currencyPositionsList = json.data.data.lists;
                    this.currencyPositionsTotal = json.data.data.count;
                } else {
                    this.$message.error("加载数据失败");
                }
            });
        },
        getInoutGoldList(ServerWhere) { //获取出入金记录数据
            var that = this.$data;
            if (!ServerWhere || ServerWhere == undefined || ServerWhere.length <= 0) {
                ServerWhere = {
                    limit: that.InoutGoldPageSize,
                    page: that.InoutGoldCurrPage,
                    account_id: that.tabAccountId,
                };
            }
            get("/Grid/QuantifyAccount/getInoutGoldList", ServerWhere, json => {
                console.log(json);
                if (json.data.code == 10000) {
                    this.InoutGoldList = json.data.data.data;
                    this.InoutGoldTotal = json.data.data.count;
                } else {
                    this.$message.error("加载数据失败");
                }
            });
        },
        getProfitGoldList(ServerWhere) { //获取分润记录数据
            var that = this.$data;
            if (!ServerWhere || ServerWhere == undefined || ServerWhere.length <= 0) {
                ServerWhere = {
                    limit: that.profitGoldPageSize,
                    page: that.profitGoldCurrPage,
                    account_id: that.tabAccountId,
                };
            }
            get("/Grid/QuantifyAccount/getDividendRecordList", ServerWhere, json => {
                console.log(json);
                if (json.data.code == 10000) {
                    this.profitGoldList = json.data.data.data;
                    this.profitGoldTotal = json.data.data.count;
                } else {
                    this.$message.error("加载数据失败");
                }
            });
        },
        InoutGoldLimitPaging(limit) {
            //赋值当前条数
            this.InoutGoldPageSize = limit;
            this.getInoutGoldList(); //刷新列表
        },
        InoutGoldSkipPaging(page) {
            //赋值当前页数
            this.InoutGoldCurrPage = page;
            this.getInoutGoldList(); //刷新列表
        },
        profitGoldLimitPaging(limit) {
            //赋值当前条数
            this.profitGoldPageSize = limit;
            this.getProfitGoldList(); //刷新列表
        },
        profitGoldSkipPaging(page) {
            //赋值当前页数
            this.profitGoldCurrPage = page;
            this.getProfitGoldList(); //刷新列表
        },
        accountCurrencyDetailsLimitPaging(limit) {
            //赋值当前条数
            this.accountCurrencyDetailsLimit = limit;
            this.getAccountCurrencyDetailsList(); //刷新列表
        },
        accountCurrencyDetailsSkipPaging(page) {
            //赋值当前页数
            this.accountCurrencyDetailsPage = page;
            this.getAccountCurrencyDetailsList(); //刷新列表
        },
        accountBalanceLimitPaging(limit) {
            //赋值当前条数
            this.accountBalanceDetailsLimit = limit;
            this.accountBalanceDetailsFun(); //刷新列表
        },
        accountBalanceSkipPaging(page) {
            //赋值当前页数
            this.accountBalanceDetailsPage = page;
            this.accountBalanceDetailsFun(); //刷新列表
        },
        currencyPositionsLimitPaging(limit) {
            this.currencyPositionsLimit = limit;
            this.getAccountCurrencyPositionsList();
        },  
        currencyPositionsSkipPaging(page) {
            this.currencyPositionsPage = page;
            this.getAccountCurrencyPositionsList();
        },
        resetForm(formName) {
            this.$refs[formName].resetFields();
        },
        DepositWithdrawalShow() { //出入金 弹框显示\
            this.dialogVisibleShow = true;
        },
        addQuantityAccount() {
            this.addQuantityAccountShow = true;
        },
        tabsHandleClick(tab, event) { //tab切换
            console.log(tab.$attrs['data-id'], event);
            this.tabAccountId = tab.$attrs['data-id'];
            this.pageSize = 20;
            this.currPage = 1;
            this.tableData = [];
            if(this.tabAccountId <= 0) {
                this.getAllList();
            } else {
                this.getList();
            }
        },
        shareProfitShow() { //分润 弹框
            this.profitShow = true;
        },
        shareProfitRecordShow() { //分润记录
            this.profitListShow = true;
            this.getProfitGoldList();
        },
        submitProfitForm(formName) { //分润
            this.$refs[formName].validate((valid) => {
                if (valid) {
                    const loading = this.$loading({
                        target: '.profit-loading',
                    });
                    this.loading = true;
                    get('/Grid/QuantifyAccount/calcDividendRecord', {
                        account_id: this.tabAccountId,
                        amount: this.ruleProfitForm.amount,
                        remark: this.ruleProfitForm.remark,
                    }, (json) => {
                        console.log(json);
                        this.loading = false;
                        this.profitShow = false;
                        if (json.data && json.data.code == 10000) {
                            this.$message.success('更新成功');
                            this.$refs[formName].resetFields();
                            loading.close();
                            this.getList();
                        } else {
                            loading.close();
                            this.$message.error(json.data.msg);
                        }
                    })
                } else {
                    console.log('error submit!!');
                    return false;
                }
            });
        },
        getMaxMinUplRate() { //获取收益率最大最小历史记录
            get("/Grid/QuantifyAccount/getMaxMinUplRateData", {
                limit: this.maxMinUplRateLimit,
                page: this.maxMinUplRatePage,
                account_id: this.tabAccountId,
                currency: 'GMX',
            }, json => {
                console.log(json);
                // this.maxMinUplRateShow = true;
                if (json.data.code == 10000) {
                    this.maxMinUplRateList = json.data.data.lists;
                    this.maxMinUplRateTotal = json.data.data.count;
                } else {
                    this.$message.error("加载数据失败");
                }
            });
        },
        maxMinUplRateLimitPaging(limit) {
            //赋值当前条数
            this.maxMinUplRateLimit = limit;
            this.getMaxMinUplRate(); //刷新列表
        },
        maxMinUplRatePaging(page) {
            //赋值当前页数
            this.maxMinUplRatePage = page;
            this.getMaxMinUplRate(); //刷新列表
        },
    },
    mounted() {

    },
}
</script>
<style lang="scss" scoped>
     .container {
            width: 100%;
            padding-top: 0;
            .el-table {
                font-size: 10、2px;
            }
            .el-tabs__item {
                font-size: 12px;
            }
            .el-descriptions {
                margin-bottom: 20px;
                .el-descriptions__body {
                    padding: 20px;
                    border-radius: 20px;
                    .el-descriptions-item__container {
                        .el-descriptions-item__content {
                            display: unset;
                            text-align: right;
                            .operate {
                                text-align: center;
                                button {
                                    width: 80px;
                                }
                            }
                        }
                    }
                }
            }
            .cache-position-summary {
                display: flex;
                align-items: center;
                gap: 24px;
                margin-bottom: 12px;
                color: #606266;
                font-size: 14px;
            }
    }
</style>



